async (params, browser) => {
  // Search for author profiles
  await browser.open(`https://scholar.google.com/citations?view_op=search_authors&mauthors=${params.query}&hl=en`)

  // Wait for author results
  await browser.waitForSelector('.gsc_1usr, #gsc_sa_ccl', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more profiles
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract author profiles
  const profiles_data = await browser.evaluate(`const profiles = []; const items = document.querySelectorAll('.gsc_1usr'); for (let i = 0; i < Math.min(items.length, 10); i++) { const el = items[i]; const nameEl = el.querySelector('.gs_ai_name a'); const affiliationEl = el.querySelector('.gs_ai_aff'); const interestEls = el.querySelectorAll('.gs_ai_one_int'); const citedByEl = el.querySelector('.gs_ai_cby'); const imgEl = el.querySelector('.gs_ai_pho img'); const interests = []; interestEls.forEach(function(intEl) { interests.push(intEl.textContent.trim()); }); const profileLink = nameEl ? nameEl.getAttribute('href') : ''; const userId = profileLink ? (profileLink.match(/user=([^&]+)/) || [])[1] || '' : ''; profiles.push({ name: nameEl ? nameEl.textContent.trim() : '', affiliation: affiliationEl ? affiliationEl.textContent.trim() : '', interests: interests, cited_by: citedByEl ? citedByEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '', user_id: userId, profile_url: profileLink ? 'https://scholar.google.com' + profileLink : '' }); } var params = new URLSearchParams(window.location.search); return { query: params.get('mauthors') || '', result_count: profiles.length, profiles: profiles }`)

  return profiles_data
}
